function same(value) {
  return {
    es: value,
    pl: value,
    de: value,
    da: value,
    no: value,
  };
}

function age(value) {
  return {
    es: `${value} años`,
    pl: `${value} lat`,
    de: `${value} Jahre alt`,
    da: `${value} år`,
    no: `${value} år`,
  };
}

